CREATE USER IF NOT EXISTS "SA" SALT '190ac682d00d4f42' HASH 'fd18d64a2c602f78212ee2e04880bb6176764d7d14ab7cc9d90c1b28ec1d31f3' ADMIN;         
CREATE CACHED TABLE "PUBLIC"."TASK"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 31) NOT NULL,
    "ASSIGNED_TO" CHARACTER VARYING(255),
    "CREATED_AT" TIMESTAMP(6) WITH TIME ZONE,
    "DESCRIPTION" CHARACTER VARYING(255),
    "PRIORITY" ENUM('CRITICAL', 'HIGH', 'LOW', 'MEDIUM') NOT NULL,
    "STATUS" ENUM('DONE', 'IN_PROGRESS', 'TODO'),
    "TITLE" CHARACTER VARYING(255),
    "UPDATED_AT" TIMESTAMP(6) WITH TIME ZONE
);             
ALTER TABLE "PUBLIC"."TASK" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_2" PRIMARY KEY("ID");         
-- 30 +/- SELECT COUNT(*) FROM PUBLIC.TASK;   
CREATE CACHED TABLE "PUBLIC"."TASK_TAGS"(
    "TASK_ID" BIGINT NOT NULL,
    "TAG" CHARACTER VARYING(255)
);               
-- 60 +/- SELECT COUNT(*) FROM PUBLIC.TASK_TAGS;              
CREATE CACHED TABLE "PUBLIC"."TASK_COMMENT"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 40) NOT NULL,
    "CONTENT" CHARACTER VARYING(255),
    "CREATED_AT" TIMESTAMP(6) WITH TIME ZONE,
    "CREATED_BY" CHARACTER VARYING(255),
    "CREATED_BY_FULL_NAME" CHARACTER VARYING(255),
    "UPDATED_AT" TIMESTAMP(6) WITH TIME ZONE,
    "TASK_ID" BIGINT
);           
ALTER TABLE "PUBLIC"."TASK_COMMENT" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_E" PRIMARY KEY("ID"); 
-- 39 +/- SELECT COUNT(*) FROM PUBLIC.TASK_COMMENT;           
CREATE CACHED TABLE "PUBLIC"."USERS"(
    "ID" BIGINT GENERATED BY DEFAULT AS IDENTITY(START WITH 1 RESTART WITH 6) NOT NULL,
    "FULLNAME" CHARACTER VARYING(255),
    "PASSWORD" CHARACTER VARYING(255),
    "ROLE" ENUM('ADMIN', 'USER'),
    "USERNAME" CHARACTER VARYING(255)
);  
ALTER TABLE "PUBLIC"."USERS" ADD CONSTRAINT "PUBLIC"."CONSTRAINT_4" PRIMARY KEY("ID");        
