ALTER TABLE "PUBLIC"."TASK_TAGS" ADD CONSTRAINT "PUBLIC"."FK5JRUFOP0GTXFEYBB27JKOQN9R" FOREIGN KEY("TASK_ID") REFERENCES "PUBLIC"."TASK"("ID") NOCHECK;       
